/**
 * Colour-code application boxes in a diagram given a lookup list.
 * Inputs:
 *  - diagramJsonString: the large JSON string you pasted (the diagram)
 *  - lookupArray: an array of objects with keys:
 *      DisplayID (e.g., "APP006"), Name, ManagementStrategy,
 *      ApplicationSuitability (1..5, may be "3.5"), BusinessCriticality (1..5),
 *      EstimatedAnnualOpex (number or numeric string)
 *
 * Outputs:
 *  {
 *    byStrategy:   <diagram object coloured by ManagementStrategy>,
 *    bySuitability:<diagram object coloured by ApplicationSuitability>,
 *    byCriticality:<diagram object coloured by BusinessCriticality>,
 *    byOpex:       <diagram object coloured by EstimatedAnnualOpex>
 *  }
 */
function colourCodeDiagrams(diagramJsonString, lookupArray) {
  // --- Parse and clone helpers ------------------------------------------------
  const parseDiagram = (s) => {
    if (typeof s === 'string') return JSON.parse(s);
    return s;
  };
  const deepClone = (obj) => JSON.parse(JSON.stringify(obj));

  const diagram = parseDiagram(diagramJsonString);

  // --- Index the lookup by DisplayID (APPnnn) and by Name ---------------------
  const normaliseId = (s) => String(s || '').trim().toUpperCase();
  const normaliseName = (s) => String(s || '').trim().toLowerCase();

  const byId = new Map();
  const byName = new Map();
  for (const row of lookupArray || []) {
    const id = normaliseId(row.DisplayID);
    const nm = normaliseName(row.Name);
    if (id) byId.set(id, row);
    if (nm) byName.set(nm, row);
  }

  // --- Extract APPnnn from a diagram box id (e.g., "app-bus-...-app006-...") --
  const extractDisplayIdFromBoxId = (boxId) => {
    const m = String(boxId || '').match(/app(\d{3})/i);
    if (!m) return null;
    return `APP${m[1]}`;
  };

  // --- Find the matching lookup row for a box ---------------------------------
  const findLookupForBox = (box) => {
    // Try by APPnnn in id
    const appId = extractDisplayIdFromBoxId(box.id);
    if (appId && byId.has(appId)) return byId.get(appId);

    // Fallback by Name (bodyText)
    const nm = normaliseName(box.bodyText);
    if (nm && byName.has(nm)) return byName.get(nm);

    return null;
  };

  // --- Colour utilities -------------------------------------------------------
  const clamp = (v, min, max) => Math.max(min, Math.min(max, v));

  // Interpolate two hex colours (sRGB) t in [0,1]
  function lerpHex(a, b, t) {
    const pa = hexToRgb(a), pb = hexToRgb(b);
    const r = Math.round(pa.r + (pb.r - pa.r) * t);
    const g = Math.round(pa.g + (pb.g - pa.g) * t);
    const bl = Math.round(pa.b + (pb.b - pa.b) * t);
    return rgbToHex(r, g, bl);
  }
  function hexToRgb(hex) {
    const h = hex.replace('#', '');
    const bigint = parseInt(h, 16);
    return { r: (bigint >> 16) & 255, g: (bigint >> 8) & 255, b: bigint & 255 };
  }
  function rgbToHex(r, g, b) {
    return '#' + [r, g, b].map((x) => x.toString(16).padStart(2, '0')).join('');
  }

  // Sequential scale: light → dark (adjust endpoints if you like)
  const SEQ_START = '#e6f0ff'; // light
  const SEQ_END   = '#003b8f'; // dark

  // Map 1..5 (or any numeric range) to a colour along the sequential scale
  function scaledColour(value, min, max) {
    if (value == null || isNaN(value)) return '#D1D5DB'; // neutral grey for N/A
    const t = clamp((Number(value) - min) / (max - min || 1), 0, 1);
    return lerpHex(SEQ_START, SEQ_END, t);
  }

  // Categorical palette for Management Strategy (edit as needed)
  const STRAT_COLOURS = {
    Resolve:  '#ef4444', // red
    Mitigate: '#f59e0b', // amber
    Optimise: '#10b981', // green
    Retire:   '#6b7280', // grey
    Tolerate: '#3b82f6', // blue
  };
  const DEFAULT_CAT = '#D1D5DB'; // neutral grey for unknown categories

  // --- Calculate domain extents for numeric scales ----------------------------
  // Suitability and Criticality are on 1..5, but we will compute from data to be safe.
  let minSuit = +Infinity, maxSuit = -Infinity;
  let minCrit = +Infinity, maxCrit = -Infinity;
  let minOpex = +Infinity, maxOpex = -Infinity;

  for (const row of lookupArray || []) {
    const s = parseFloat(row.ApplicationSuitability);
    const c = parseFloat(row.BusinessCriticality);
    const o = parseFloat(row.EstimatedAnnualOpex);

    if (!isNaN(s)) { minSuit = Math.min(minSuit, s); maxSuit = Math.max(maxSuit, s); }
    if (!isNaN(c)) { minCrit = Math.min(minCrit, c); maxCrit = Math.max(maxCrit, c); }
    if (!isNaN(o)) { minOpex = Math.min(minOpex, o); maxOpex = Math.max(maxOpex, o); }
  }
  // Sensible fallbacks if data are missing
  if (!isFinite(minSuit)) { minSuit = 1; maxSuit = 5; }
  if (!isFinite(minCrit)) { minCrit = 1; maxCrit = 5; }
  if (!isFinite(minOpex)) { minOpex = 0; maxOpex = 1; }

  // --- Core colour-application function --------------------------------------
  function colourise(clone, colourPicker) {
    for (const box of clone.boxes || []) {
      if (box.stencil !== 'physicalApplication') continue; // only colour app boxes
      const row = findLookupForBox(box);
      const colour = colourPicker(row);
      if (colour) box.backgroundColor = colour;
      else box.backgroundColor = '#D1D5DB'; // unmatched → neutral grey
    }
    return clone;
  }

  // --- Build the four variants ------------------------------------------------
  const byStrategy    = colourise(deepClone(diagram), (row) =>
    row ? (STRAT_COLOURS[row.ManagementStrategy] || DEFAULT_CAT) : null
  );

  const bySuitability = colourise(deepClone(diagram), (row) =>
    row ? scaledColour(parseFloat(row.ApplicationSuitability), minSuit, maxSuit) : null
  );

  const byCriticality = colourise(deepClone(diagram), (row) =>
    row ? scaledColour(parseFloat(row.BusinessCriticality), minCrit, maxCrit) : null
  );

  const byOpex        = colourise(deepClone(diagram), (row) =>
    row ? scaledColour(parseFloat(row.EstimatedAnnualOpex), minOpex, maxOpex) : null
  );

  return { byStrategy, bySuitability, byCriticality, byOpex };
}

// ------------------------------
// Example usage:
//
// const diagramJsonString = `...` // your huge JSON string from the prompt
// const lookupArray = [ { DisplayID:"APP005", Name:"AB Note", ... }, ... ];
//
// const { byStrategy, bySuitability, byCriticality, byOpex } = colourCodeDiagrams(diagramJsonString, lookupArray);
//
// // If you need strings again:
// const out1 = JSON.stringify(byStrategy);
// const out2 = JSON.stringify(bySuitability);
// const out3 = JSON.stringify(byCriticality);
// const out4 = JSON.stringify(byOpex);
//
// console.log(out1, out2, out3, out4);
// ------------------------------

/************************************************************
 * Application-Colour-Mapper (all-in-one)
 * Input:  many DB items  (DisplayID, Name, ManagementStrategy, etc.)
 * Output:  4 items  (by Strategy, Suitability, Criticality, Opex)
 ************************************************************/

// ====== 1. CONFIGURATION ==================================
// Diagram JSON is retrieved from workflow variable set by 'Store Diagram Variable' node
const DIAGRAM_JSON = $workflowData.variables.diagramJson;
if (!DIAGRAM_JSON) {
  throw new Error('Diagram variable not set. Ensure Store Diagram Variable node executed successfully.');
}
// If diagram is already a string, use it; if it's an object, stringify it
const diagramToUse = typeof DIAGRAM_JSON === 'string' ? DIAGRAM_JSON : JSON.stringify(DIAGRAM_JSON);


const STRAT_COLOURS = {
  Resolve:  '#ef4444',
  Mitigate: '#f59e0b',
  Optimise: '#10b981',
  Retire:   '#6b7280',
  Tolerate: '#3b82f6',
  Divest:   '#8b5cf6',   // violet
};
const NEUTRAL = '#D1D5DB';
const SEQ_START = '#e6f0ff'; // light
const SEQ_END   = '#003b8f'; // dark
// ===========================================================


// ---- 2. BUILD LOOKUP ARRAY FROM 309 DB ROWS ---------------
function num(x){ const n = Number(x); return Number.isFinite(n)?n:undefined; }
function txt(x){ return x == null ? undefined : String(x).trim(); }

const lookup = items.map(({json}) => ({
  DisplayID: txt(json.DisplayID)?.toUpperCase(),
  Name: txt(json.Name),
  ManagementStrategy: txt(json.ManagementStrategy),
  ApplicationSuitability: num(json.ApplicationSuitability),
  BusinessCriticality: num(json.BusinessCriticality),
  EstimatedAnnualOpex: num(json.EstimatedAnnualOpex),
}));


// ---- 3. HELPER UTILITIES ---------------------------------
const normId   = s => String(s||'').trim().toUpperCase();
const normName = s => String(s||'').trim().toLowerCase();
const clamp = (v,a,b)=>Math.max(a,Math.min(b,v));

const hexToRgb = h=>{
  const n=parseInt(h.replace('#',''),16);
  return {r:(n>>16)&255,g:(n>>8)&255,b:n&255};
};
const rgbToHex=(r,g,b)=>
  '#'+[r,g,b].map(x=>x.toString(16).padStart(2,'0')).join('');
const lerpHex=(a,b,t)=>{
  const A=hexToRgb(a),B=hexToRgb(b);
  const r=Math.round(A.r+(B.r-A.r)*t);
  const g=Math.round(A.g+(B.g-A.g)*t);
  const bl=Math.round(A.b+(B.b-A.b)*t);
  return rgbToHex(r,g,bl);
};
const scaleColour=(x,min,max)=>
  isNaN(x)?NEUTRAL:lerpHex(SEQ_START,SEQ_END,clamp((x-min)/(max-min||1),0,1));

// Index lookup by DisplayID and Name
const byId=new Map(), byName=new Map();
for(const r of lookup){
  if(r.DisplayID) byId.set(normId(r.DisplayID),r);
  if(r.Name) byName.set(normName(r.Name),r);
}

const idFromBox=id=>{
  const m=String(id||'').match(/app(\d{3})/i);
  return m?`APP${m[1]}`:null;
};
function findRow(box){
  const app=idFromBox(box.id);
  if(app&&byId.has(app)) return byId.get(app);
  const nm=normName(box.bodyText);
  return byName.get(nm);
}


// ---- 4. DOMAIN CALCULATIONS -------------------------------
let minS=Infinity,maxS=-Infinity,minC=Infinity,maxC=-Infinity,minO=Infinity,maxO=-Infinity;
for(const r of lookup){
  const s=r.ApplicationSuitability,c=r.BusinessCriticality,o=r.EstimatedAnnualOpex;
  if(!isNaN(s)){minS=Math.min(minS,s);maxS=Math.max(maxS,s);}
  if(!isNaN(c)){minC=Math.min(minC,c);maxC=Math.max(maxC,c);}
  if(!isNaN(o)){minO=Math.min(minO,o);maxO=Math.max(maxO,o);}
}
if(!isFinite(minS)){minS=1;maxS=5;}
if(!isFinite(minC)){minC=1;maxC=5;}
if(!isFinite(minO)){minO=0;maxO=1;}


// ---- 5. COLOURING FUNCTION --------------------------------
function applyColours(diagram,picker){
  const d=typeof diagram==='string'?JSON.parse(diagram):structuredClone(diagram);
  for(const box of d.boxes||[]){
    if(box.stencil!=='physicalApplication') continue;
    const row=findRow(box);
    box.backgroundColor=picker(row);
  }
  return d;
}


// ---- 6. GENERATE VARIANTS ---------------------------------
const diagramObj = JSON.parse(DIAGRAM_JSON);

const byStrategy = applyColours(diagramObj, r =>
  r ? (STRAT_COLOURS[r.ManagementStrategy] ?? NEUTRAL) : NEUTRAL
);
const bySuitability = applyColours(diagramObj, r =>
  r ? scaleColour(r.ApplicationSuitability, minS, maxS) : NEUTRAL
);
const byCriticality = applyColours(diagramObj, r =>
  r ? scaleColour(r.BusinessCriticality, minC, maxC) : NEUTRAL
);
const byOpex = applyColours(diagramObj, r =>
  r ? scaleColour(r.EstimatedAnnualOpex, minO, maxO) : NEUTRAL
);


// ---- 7. RETURN FOUR ITEMS ---------------------------------
return [
  {json:{view:'ManagementStrategy',diagram:byStrategy}},
  {json:{view:'ApplicationSuitability',diagram:bySuitability}},
  {json:{view:'BusinessCriticality',diagram:byCriticality}},
  {json:{view:'EstimatedAnnualOpex',diagram:byOpex}},
];
